    43	const int get_ul_tda(gNB_MAC_INST *nrmac, const NR_ServingCellConfigCommon_t *scc, int frame, int slot)
    44	{
    45	  /* we assume that this function is mutex-protected from outside */
    46	  NR_SCHED_ENSURE_LOCKED(&nrmac->sched_lock);
    47	
    48	  /* there is a mixed slot only when in TDD */
    49	  const NR_TDD_UL_DL_Pattern_t *tdd = scc->tdd_UL_DL_ConfigurationCommon ? &scc->tdd_UL_DL_ConfigurationCommon->pattern1 : NULL;
    50	  AssertFatal(tdd || nrmac->common_channels->frame_type == FDD, "Dynamic TDD not handled yet\n");
    51	
    52	  if (tdd && tdd->nrofUplinkSymbols > 1) { // if there is uplink symbols in mixed slot
    53	    const int nr_slots_period = tdd->nrofDownlinkSlots + tdd->nrofUplinkSlots + 1;
    54	    if ((slot % nr_slots_period) == tdd->nrofDownlinkSlots)
    55	      return 2;
    56	  }
    57	
    58	  // Avoid slots with the SRS
    59	  UE_iterator(nrmac->UE_info.list, UE) {
    60	    NR_sched_srs_t sched_srs = UE->UE_sched_ctrl.sched_srs;
    61	    if(sched_srs.srs_scheduled && sched_srs.frame == frame && sched_srs.slot == slot)
    62	      return 1;
    63	  }
    64	
    65	  return 0; // if FDD or not mixed slot in TDD, for now use default TDA (TODO handle CSI-RS slots)
    66	}
