    68	static int compute_ph_factor(int mu, int tbs_bits, int rb, int n_layers, int n_symbols, int n_dmrs, long *deltaMCS)
    69	{
    70	  // 38.213 7.1.1
    71	  // if the PUSCH transmission is over more than one layer delta_tf = 0
    72	  int delta_tf = 0;
    73	  if(deltaMCS != NULL && n_layers == 1) {
    74	    const int n_re = (NR_NB_SC_PER_RB * n_symbols - n_dmrs) * rb;
    75	    const float BPRE = (float) tbs_bits/n_re;  //TODO change for PUSCH with CSI
    76	    const float f = pow(2, BPRE * 1.25);
    77	    const float beta = 1.0f; //TODO change for PUSCH with CSI
    78	    delta_tf = (10 * log10((f - 1) * beta));
    79	  }
    80	
    81	  const int bw_factor = 10 * log10(rb << mu);
    82	
    83	  return (delta_tf + bw_factor);
    84	}
